import React, { memo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const FAQ_ITEMS = [
  {
    question: "Kui kaua votab autohooldus Tallinnas aega?",
    answer: "Soltuvalt teenusest votab autohooldus Tallinnas 1-4 tundi. Lihtsamad tood nagu rehvi vahetus votavad 30-60 minutit, keerukamad remondid kuni 4 tundi."
  },
  {
    question: "Kas teete autodiagnostika Tallinnas valjaspool tooaega?",
    answer: "Jah, pakume paindlikke aegu autodiagnostika Tallinnas. Voimalik on kokku leppida ka ohtuti voi nadalavahetustel, et see sobiks teie graafikusse."
  },
  {
    question: "Milliseid garantiisid annate autohooldusele Tallinnas?",
    answer: "Anname 30-paevase garantii detailing toodetele ja 6-kuuse garantii remonditoodele. Koik too labib pohjaliku kvaliteedikontrolli."
  },
  {
    question: "Kas saate auto jarele tuua autohoolduseks Tallinnas?",
    answer: "Jah, pakume auto transporti Tallinnas ja lahiombruses. Hind soltub kaugusest ja auto suurusest."
  },
  {
    question: "Milliseid makseviise aktsepteerite autohoolduse eest Tallinnas?",
    answer: "Aktsepteerime sularaha, pangakaarti, ulekannet ja populaarseid mobiilimakseid."
  }
];

const FaqSection = memo(() => {
  return (
    <Section id="faq" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader className="text-center">
          <CardTitle asChild className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            <h2>Korduma kippuvad küsimused</h2>
          </CardTitle>
          <p className="mt-3 text-slate-800 dark:text-slate-300">Leiad vastused kõige sagedamini esitatud küsimustele meie teenuste kohta.</p>
        </CardHeader>
        <CardContent className="space-y-6">
          {FAQ_ITEMS.map((faq, index) => (
            <div key={index} className="border-b border-slate-200 dark:border-slate-700 pb-6 last:border-b-0">
              <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-100 mb-2">{faq.question}</h3>
              <p className="text-slate-800 dark:text-slate-300">{faq.answer}</p>
            </div>
          ))}
        </CardContent>
      </Card>
    </Section>
  );
});

FaqSection.displayName = 'FaqSection';

export default FaqSection;
